layout(location = 0) in vec3 a_position;
layout(location = 1) in vec2 a_texCoord;
layout(location = 2) in vec4 a_color;
layout(location = 0) out vec4 color;
layout(location = 1) out vec2 uv0;
vec4 vert () {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
  #endif
  #if USE_PIXEL_ALIGNMENT
    pos = cc_matView * pos;
    pos.xyz = floor(pos.xyz);
    pos = cc_matProj * pos;
  #else
    pos = cc_matViewProj * pos;
  #endif
  uv0 = a_texCoord;
  #if SAMPLE_FROM_RT
    uv0 = cc_cameraPos.w > 1.0 ? vec2(uv0.x, 1.0 - uv0.y) : uv0;
  #endif
  color = a_color;
  return pos;
}
void main() { gl_Position = vert(); }

glsl4.frag:
precision highp float;
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
  layout(set = 1, binding = 0) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
layout(location = 0) in vec4 color;
layout(set = 1, binding = 1) uniform Constant{
  vec4 startColor;
  vec4 endColor;
};
layout(location = 1) in vec2 uv0;
layout(set = 2, binding = 11) uniform sampler2D cc_spriteTexture;
layout(set = 1, binding = 2) uniform ARGS{
  float colorRadio;
  int gradientDirection;
  float gradientAngle;
};
vec4 frag () {
  vec4 o = vec4(1, 1, 1, 1);
  o *= CCSampleWithAlphaSeparated(cc_spriteTexture, uv0);
  float gradientCoord = 0.0;
  if (gradientDirection == 0) {
    gradientCoord = uv0.x;
  }
  else if (gradientDirection == 1) {
    gradientCoord = 1.0 - uv0.x;
  }
  else if (gradientDirection == 2) {
    gradientCoord = 1.0 - uv0.y;
  }
  else if (gradientDirection == 3) {
    gradientCoord = uv0.y;
  }
  else if (gradientDirection == 4) {
    float angleRad = radians(gradientAngle);
    vec2 direction = vec2(cos(angleRad), sin(angleRad));
    vec2 centeredUV = uv0 - 0.5;
    gradientCoord = dot(centeredUV, direction) + 0.5;
    gradientCoord = clamp(gradientCoord, 0.0, 1.0);
  }
  o.rgb *= mix(startColor.rgb, endColor.rgb, smoothstep(0.0, colorRadio * 2.0, gradientCoord));
  o *= color;
  ALPHA_TEST(o);
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }
